import { useState, useEffect } from "react";

const API_BOOKINGS = "http://localhost:9000/api/bookings";
const API_PROFILE = "http://localhost:9000/api/users/profile"; // Profile API

const initialSlots = Array.from({ length: 10 }, (_, i) => ({
  id: i + 1,
  booked: false,
}));

export default function SlotBooking() {
  const [slots, setSlots] = useState(initialSlots);
  const [selectedSlot, setSelectedSlot] = useState<number | null>(null);
  const [userDetails, setUserDetails] = useState({ name: "", phone: "" });
  const [selectedDates, setSelectedDates] = useState<string[]>([]);
  const [bookings, setBookings] = useState<
    { slot: number; dates: string[]; user: string }[]
  >([]);

  // Fetch user details and bookings on mount
  useEffect(() => {
    const fetchUserProfile = async () => {
      try {
        const response = await fetch(API_PROFILE);
        if (response.ok) {
          const userData = await response.json();
          setUserDetails({ name: userData.name, phone: userData.phone });
        } else {
          console.error("Failed to fetch user profile");
        }
      } catch (error) {
        console.error("Error fetching user profile:", error);
      }
    };

    const fetchBookings = async () => {
      try {
        const response = await fetch(API_BOOKINGS);
        if (response.ok) {
          const data = await response.json();
          setBookings(data);

          // Update slot availability
          setSlots((prevSlots) =>
            prevSlots.map((slot) => ({
              ...slot,
              booked: data.some((booking: any) => booking.slot === slot.id),
            }))
          );
        } else {
          console.error("Failed to fetch bookings");
        }
      } catch (error) {
        console.error("Error fetching bookings:", error);
      }
    };

    fetchUserProfile();
    fetchBookings();
  }, []);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setUserDetails({ ...userDetails, [e.target.name]: e.target.value });
  };

  const handleSlotSelect = (id: number) => {
    if (!slots.find((slot) => slot.id === id)?.booked) {
      setSelectedSlot(id);
    }
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const date = e.target.value;
    setSelectedDates((prev) =>
      prev.includes(date) ? prev.filter((d) => d !== date) : [...prev, date]
    );
  };

  const handleBooking = async () => {
    if (
      !selectedSlot ||
      selectedDates.length === 0 ||
      !userDetails.phone ||
      !userDetails.name
    ) {
      alert("Please fill in all details and select a slot and date.");
      return;
    }

    try {
      const response = await fetch(API_BOOKINGS, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: userDetails.name,
          phone: userDetails.phone,
          slot: selectedSlot,
          dates: selectedDates,
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        alert(errorData.error);
        return;
      }

      alert("Booking confirmed!");
      window.location.reload(); // Refresh to update slots
    } catch (error) {
      console.error("Error booking slot", error);
    }
  };

  return (
    <div className="flex flex-col items-center p-6 bg-gray-100 min-h-screen">
      <h1 className="text-2xl font-bold mb-4">Bike Parking Slot Booking</h1>

      {/* User Details Form */}
      <div className="bg-white p-6 rounded-lg shadow-lg w-80">
        <label className="block mb-2 font-semibold">Name</label>
        <input
          type="text"
          name="name"
          value={userDetails.name}
          onChange={handleInputChange}
          className="w-full p-2 border rounded mb-4"
        />
        <label className="block mb-2 font-semibold">Phone</label>
        <input
          type="text"
          name="phone"
          value={userDetails.phone}
          onChange={handleInputChange}
          className="w-full p-2 border rounded mb-4"
        />
      </div>

      {/* Slots Grid */}
      <div className="grid grid-cols-5 gap-4 bg-white p-6 rounded-lg shadow-lg mt-6">
        {slots.map((slot) => (
          <button
            key={slot.id}
            className={`w-12 h-12 rounded-md flex items-center justify-center text-white font-bold cursor-pointer transition-all ${
              slot.booked
                ? "bg-gray-400 cursor-not-allowed"
                : selectedSlot === slot.id
                ? "bg-blue-500"
                : "bg-green-500"
            }`}
            onClick={() => handleSlotSelect(slot.id)}
            disabled={slot.booked}
          >
            {slot.id}
          </button>
        ))}
      </div>

      {/* Date Picker */}
      <div className="mt-6 p-4 bg-white rounded-lg shadow-md w-80 text-center">
        <h2 className="text-lg font-semibold">Select Dates</h2>
        <input
          type="date"
          onChange={handleDateChange}
          className="mt-2 p-2 border rounded w-full"
        />
        <p className="mt-2 text-gray-500">
          Selected Dates: {selectedDates.join(", ")}
        </p>
      </div>

      {/* Booking Button */}
      <button
        onClick={handleBooking}
        className="mt-4 px-6 py-2 bg-blue-600 text-white rounded-lg shadow-md hover:bg-blue-700"
      >
        Book Slot
      </button>
    </div>
  );
}
